	.TITLE	TMIDI	.PROC	M680002	.REF	SMAKY	.LOC	0ONDMIDI:.BLKB	2		; no du driver MIDIONIMIDI:.BLKB	1		; 1 => driver MIDI pas install ici	.EVENOFLAGS:	.BLKB	1 BWAIT32 = 0	.EVENOLWAIT:	.BLKB	4OBMIDI:	.BLKB	5000LGVAR:	.LOC	0START:	LOAD.L	A6,#R16"VAR	LOAD.L	A4,A6	LOAD.W	D4,#LGVAR10$:	CLR.B	(A4+)	DEC.W	D4	JUMP,NE 10$	CALL	OPEMIDI	JUMP,NE ERFAT	CALL	WAIT32	LOAD.L	A4,#(A6)+OBMIDI	LOAD.L	D2,(A6)+OLWAIT	LIB	?AFCR	LOAD.L	D4,D2	LIB	?AFX8	LIB	?AFCR	ADD.L	A4,#4+11+64+3	SUB.L	D2,#4+11+64+3	JUMP,LE 50$40$:	CALL	AFNOM	LIB	?AFSPACE	ADD.L	A4,#128+3	SUB.L	D2,#128+3	JUMP,LE 50$	JUMP	40$50$:JUMP 70$	LIB	?GETCAR	LOAD.L	A4,#(A6)+OBMIDI	LOAD.L	D2,(A6)+OLWAIT	LIB	?AFCR60$:	TEST.L	D2	JUMP,EQ 70$	LOAD.B	D4,(A4+)	LIB	?AFX2	LIB	?AFSPACE	DEC.L	D2	JUMP	60$70$:	CALL	STOPMIDI	CALL	CLOMIDI	EXITERFAT:	LIB	?AFTIM	.ASCIZ	"--ERREUR--"	.EVEN	EXITAFNOM:	PUSHM.L	D3,D4,A4	LOAD.W	D4,#710$:	CALL	AFCAR	DEC.W	D4	JUMP,NE 10$	POPM.L	D3,D4,A4	RETAFCAR:	LOAD.B	D3,(A4)+1	SL.B	D3,#4	OR.B	D3,(A4)+0	ADD.L	A4,#2	LIB	?AFCODE	RET;--------\\; WRMIDI  >;========/; ; in	A4.L	^data; out	D7.W	erreur; mod	D7.WWRMIDI:	PUSHM.L	D2,D5	CLR.L	D5	LOAD.W	D5,(A4)	ADD.W	D5,#2	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DWRITE		; crit tout a	POPM.L	D2,D5	TEST.W	D7		; retour EQ/NE	RETWAIT32:LIB ?AFTIM.ASCIZ "a".EVEN	TSET.B	(A6)+OFLAGS:#BWAIT32	NTREL	?GETPRIO	; D4 <-- priorit	DEC.W	D4	LOAD.L	D5,#600		; D5 <-- lg stack	LOAD.L	A5,#R16"PWAIT32	; A5 <-- ^start	LOAD.L	A3,#R16"NWAIT32	; A3 <-- ^nom	NTREL	?CRETASK	; dmarre la rception	JUMP,NE 90$LIB ?AFTIM.ASCIZ "b".EVEN30$:	LIB	?IFCAR		; vide le fifo du clavier !	JUMP,EQ 30$	LOAD.L	A4,#R16"00$	CALL	WRMIDI	LOAD.W	D2,#10*2	; D2 <-- attend 2 secondes maximum40$:LIB ?AFTIM.ASCIZ "c".EVEN	CLR.W	D7		; D7 <-- ok	TEST.B	(A6)+OFLAGS:#BWAIT32	JUMP,BC 45$	LIB	?IFCAR		; touche presse ?	JUMP,EQ 44$		; oui => 44$	LOAD.W	D4,#50/10	NTREL	?DELMS		; attend un peu ...	DEC.W	D2	JUMP,NE 40$44$:	LOAD.W	D7,#ERUNCO	; D7 <-- unit pas connecte45$:LIB ?AFTIM.ASCIZ "s".EVEN	PUSH.W	D7	CALL	STOPMIDI	; stoppe tout	POP.W	D7	JUMP,NE 90$	LOAD.W	D7,#ERUNCO	; D7 <-- unit pas (ou mal) connecte	LOAD.L	A4,#(A6)+OBMIDI	; A4 <-- ^data reu	LOAD.L	D4,(A6)+OLWAIT	; D4 <-- lg data reu50$:90$:LIB ?AFTIM.ASCIZ "d".EVEN	RET00$:	.B	0,8	.B	H'F0	.B	H'43	.B	H'75	.B	H'00	.B	H'20	.B	H'00	.B	H'06	.B	H'F7	.EVEN;;;;;;;;;;;;;;;    WAIT    ;;;;;;;;;;;;;;;NWAIT32:.ASCIZ	"MIDI_WAIT32"	.EVENPWAIT32:LIB ?AFTIM.ASCIZ " (fils) ".EVEN	LOAD.L	A4,#(A6)+OBMIDI	LOAD.L	D5,#4+11+2*(H'22+48*H'42)+2	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DREAD	LOAD.L	(A6)+OLWAIT,D5LIB ?AFTIM.ASCIZ " (end) ".EVEN	TCLR.B	(A6)+OFLAGS:#BWAIT32	NTREL	?ABORT;--------\\; COMMAND >;========/; Envoie une commande  MIDI.; in	A4.L	^commande; out	D7.W	erreur; mod	D7.WCOMMAND:	PUSHM.L	D1,D2	LOAD.W	D1,#TYPIO	; D1 <-- type	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DCOMMAND	POPM.L	D1,D2	TEST.W	D7		; retour EQ/NE	RET;---------\\; STOPMIDI >;=========/; Stoppe compltement MIDI.; in	-; out	-; mod	D7.WSTOPMIDI:	PUSH.L	D2	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DAVOTR		; avort lecture/criture;;?	NTREL	?WFABDESC	; attend la fin des processus fils	POP.L	D2	RET;--------\\; OPEMIDI >;========/; Ouvre le driver MIDI.; in	-; out	D7.W	erreur; mod	D7.WOPEMIDI:	PUSHM.L	D2,D3,A2..A4; Dinstalle l'usart en utilisant les noms #PR, #PP, #MI et #MO.	LOAD.L	A3,#R16"LUSART0	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	LOAD.L	A3,#R16"LUSART1;	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	LOAD.L	A3,#R16"LUSART2;	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	LOAD.L	A3,#R16"LUSART3;	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL; Installe le driver MIDI  la place de l'usart.	CLR.B	(A6)+ONIMIDI	; driver MIDI install ici	LOAD.L	A3,#R16"LMIDI	; A3 <-- ^nom logique	LOAD.L	A4,#R16"PMIDI	; A4 <-- ^nom physique	LOAD.L	A2,#0		; A2 <-- ^paramtres;	CLR.W	D3		; D3 <-- pour tous	FOS	?INSTALL	; install le driver	JUMP,EQ 50$	COMP.W	D7,#ERUUSE	; dj install ?	JUMP,NE	90$		; non => 90$				; oui =>	SET.B	(A6)+ONIMIDI	; driver MIDI pas install ici50$:	LOAD.L	A3,#R16"DMIDI	FOS	?UNAMDRIV	; D2 <-- numro de driver	JUMP,NE	90$	LOAD.W	(A6)+ONDMIDI,D2	90$:	POPM.L	D2,D3,A2..A4	TEST.W	D7		; retour EQ/NE	RET;--------\\; CLOMIDI >;========/; Ferme le driver MIDI.; in	-; out	-; mod	D7.WCLOMIDI:	PUSHM.L	D3,A3	TEST.B	(A6)+ONIMIDI	; driver MIDI install ici ?	JUMP,T	90$		; non => 90$	LOAD.L	A3,#R16"LMIDI	; A3 <-- ^nom logique	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	; dinstall le driver90$:	POPM.L	D3,A3	RET; Textes; ------LUSART0:.ASCIZ	"#PR"LUSART1:.ASCIZ	"#PP"LUSART2:.ASCIZ	"#MI"LUSART3:.ASCIZ	"#MO"LMIDI:	.ASCIZ	"#MIDI:"PMIDI:	.ASCIZ	"$MIDI_0"DMIDI:	.ASCIZ	"MIDI_0"	.EVENVAR:	.FILLB	LGVAR,0	.END	START